def _use_q1_tile_reduce(inputs: dict[str, Any]) -> bool:
    return lowq._use_q1_tile_reduce(inputs)

def _use_lowq_tile_reduce(inputs: dict[str, Any]) -> bool:
    return lowq._use_lowq_tile_reduce_blockm512(inputs, use_lowq_mma=lowq._use_lowq_mma(inputs)) or (lowq._use_lowq_tile_reduce(inputs) and (not lowq._use_lowq_mma(inputs)))

def _use_lowq_tcgen05(inputs: dict[str, Any]) -> bool:
    return lowq._use_lowq_mma(inputs)

def _use_lowq_d128_policy(inputs: dict[str, Any]) -> bool:
    return _use_q1_tile_reduce(inputs) or _use_lowq_tile_reduce(inputs) or _use_lowq_tcgen05(inputs)

def selected_route(inputs: dict[str, Any]) -> str:
    if _use_q1_tile_reduce(inputs):
        return 'round39_q1_tile_reduce'
    if _use_lowq_tcgen05(inputs):
        return 'round39_lowq_tcgen05_mma_split'
    if _use_lowq_tile_reduce(inputs):
        return 'round39_lowq_tile_reduce'
    return parent.selected_route(inputs)

def launch_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    if _use_lowq_d128_policy(inputs):
        return lowq.launch_for_eval(inputs)
    return parent.launch_for_eval(inputs)

def _select_contract_shapes(shape_labels: str | tuple[str, ...] | list[str] | None):
    if shape_labels is None:
        return None
    return select_named_shapes(shape_labels)

def knn_search_compile_and_launch_lowq_dispatch(*, benchmark: bool=True, shapes: list[dict[str, Any]] | None=None) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    result = evaluate(launch_for_eval, shapes=LOWQ_D128_DISPATCH_SHAPES if shapes is None else shapes, benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result

def knn_search_compile_and_launch_round39_dispatch(*, benchmark: bool=True, shapes: list[dict[str, Any]] | None=None) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    result = evaluate(launch_for_eval, shapes=ROUND39_DISPATCHER_SHAPES if shapes is None else shapes, benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result

def knn_search_compile_and_launch_round39_preserve(*, benchmark: bool=True) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    result = evaluate(launch_for_eval, shapes=ROUND39_PRESERVE_SHAPES, benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result
